const anoAtual = new Date().getFullYear();
let infoConta = { id: "", nome: "Banco - Conta" };

// 1. CAPTURA DADOS DO WEBHOOK
try {
  const webhookNode = $("Recebe link do Supabase Storage").first();
  if (webhookNode && webhookNode.json && webhookNode.json.body) {
      infoConta.id = webhookNode.json.body.accountId || "";
      infoConta.nome = `${webhookNode.json.body.bankName || "Banco"} - ${webhookNode.json.body.accountName || "Conta"}`;
  }
} catch (e) {}

const resultadosFinais = [];
const parcelamentosVistos = new Map(); 
const relatorio_erros = []; 

// 2. LOOP PRINCIPAL PELOS ITENS DA IA
const todosOsItens = $input.all();

for (let i = 0; i < todosOsItens.length; i++) {
    let item = todosOsItens[i].json;
    let transacoes = [];

    // --- ESTRATÉGIA DE CAPTURA DUPLA ---
    if (item.output && Array.isArray(item.output)) {
        transacoes = item.output;
    } 
    else {
        let textoBruto = item.text || item.message?.content || "";
        if (item.content && Array.isArray(item.content) && item.content[0]?.text) {
            textoBruto = item.content[0].text;
        }

        if (textoBruto) {
            const match = textoBruto.match(/[\{\[]([\s\S]*)[\}\]]/);
            if (match) {
                try {
                    let jsonLimpo = match[0];
                    jsonLimpo = jsonLimpo.replace(/\},\s*}/g, '} ] }').replace(/,\s*([\]}])/g, '$1');

                    const dadosParseados = JSON.parse(jsonLimpo);
                    transacoes = dadosParseados.transacoes || dadosParseados.output || (Array.isArray(dadosParseados) ? dadosParseados : []);
                } catch (parseErr) {
                    relatorio_erros.push({ erro: `Falha ao parsear string de texto na página ${i}`, detalhe: parseErr.message });
                }
            }
        }
    }

    if (!Array.isArray(transacoes) || transacoes.length === 0) {
        relatorio_erros.push({ aviso: `Não foi possível extrair transações estruturadas do item ${i}.` });
        continue;
    }

    // 3. MAPEAMENTO PADRÃO DAS TRANSAÇÕES ENCONTRADAS
    transacoes.forEach((t, index) => {
        const descOriginal = (t.t || t.descricao || "").toString().toUpperCase().trim();
        const valorOriginal = parseFloat(t.v !== undefined ? t.v : t.valor) || 0;
        const sinal = t.s || t.tipo || "";

        let valorFinal = (sinal === "-" || sinal.toLowerCase() === "despesa") ? -Math.abs(valorOriginal) : Math.abs(valorOriginal); 

        // Tratamento da Data (DD/MM/YYYY -> ISO YYYY-MM-DD)
        let dataRaw = t.d || t.data || "";
        let dataISO = dataRaw.split('-')[0].trim();
        if (dataISO.includes('/')) {
            const pDate = dataISO.split('/');
            const anoLido = pDate[2] ? pDate[2].trim() : anoAtual;
            dataISO = `${anoLido}-${pDate[1].padStart(2,'0')}-${pDate[0].padStart(2,'0')}T12:00:00`;
        }

        const p = t.p || t.parcelamento || null;

        // --- LÓGICA DE FILTRO DE DUPLICIDADE DE PARCELA ---
        const matchParcela = (p || descOriginal).match(/(\d+)\s*[\/\-de\s]+\s*(\d+)/);
        if (matchParcela) {
            const pAtual = parseInt(matchParcela[1], 10);
            const pTotal = matchParcela[2];
            const descLimpa = descOriginal.replace(/\(?\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)?/g, '').trim();
            const signature = `${descLimpa}_${valorFinal}_${pTotal}`;

            if (parcelamentosVistos.has(signature) && pAtual > parcelamentosVistos.get(signature)) return;
            parcelamentosVistos.set(signature, pAtual);
        }

        const categoriaAtual = t.c || t.categoria || "outros-gv";

        // Lista de categorias consideradas "neutras"
        const categoriasNeutras = [
            "reembolsos", 
            "estorno", 
            "pagamento-fatura-cartao", 
            "transferencia-mesma-titularidade", 
            "despesas-reembolsaveis", 
            "reserva-emergencia", 
            "projetos-vida", 
            "independencia-financeira"
        ];

        resultadosFinais.push({
            json: {
                account_id: infoConta.id,
                Conta: infoConta.nome,
                Data_lancamento: dataISO,
                Descricao: descOriginal,
                Valor: valorFinal,
                // REGRA SELEÇÃO: Se a categoria estiver na lista, é neutro. Se não estiver, obrigatoriamente despesa.
                Tipo: categoriasNeutras.includes(categoriaAtual) ? "neutro" : "despesa",
                Categoria: categoriaAtual,
                p: p,
                id_conciliacao: `ocr-${i}-${index}`,
                Data_pagamento: dataISO,
                Classificacao: categoriaAtual
            }
        });
    });
}

// 4. FILTRAGEM DE RUÍDO FINANCEIRO
const validos = resultadosFinais.filter(res => {
    const d = res.json.Descricao;
    const ignorar = ["TOTAL", "SUBTOTAL", "RESUMO", "PAGAMENTO EFETUADO", "SALDO ANTERIOR"];
    return !ignorar.some(p => d.includes(p)) && d !== "";
});

if (validos.length > 0) {
    return validos;
}

return relatorio_erros.length > 0 ? relatorio_erros.map(e => ({ json: e })) : [{ json: { aviso: "Nenhuma transação gerada." } }];

/**
 * NORMALIZADOR UNIVERSAL (PEGA TUDO O QUE CHEGAR)
 */

// 1. DADOS DA CONTA
let accountId = "";
let bankName = "";
try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) { bankName = "Banco"; }

// 2. CAPTURA DE DADOS (ABERTURA DE ENVELOPE)
let listaBruta = [];
const incomingData = $input.all();

for (const item of incomingData) {
  const data = item.json;

  // Tenta encontrar a lista de transações em qualquer lugar
  let alvo = data.output || data;

  if (Array.isArray(alvo)) {
    listaBruta = listaBruta.concat(alvo);
  } else if (typeof alvo === 'object' && (alvo.t || alvo.d)) {
    listaBruta.push(alvo);
  }
}

// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (item.s === "-" || item.s === "despesa") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);

  let dataF = item.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    dataF = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno","pagamento-fatura-cartao", "transferencia-mesma-titularidade", "despesas-reembolsaveis", "reserva-emergencia", "projetos-vida", "independencia-financeira"].includes(item.c) ? "neutro" : "receita"),
      Categoria: item.c || "outros-gv",
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});

return final;

// 1. Buscamos o binário diretamente do nó que processou o arquivo original
// Se o nó que criou o binário tiver outro nome, ajuste 'Code in JavaScript10' abaixo
const nodeComArquivo = 'Code in JavaScript6'; 

let binaryData;
try {
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data', nodeComArquivo);
} catch (e) {
    // Caso o nome acima esteja diferente, tentamos pegar do que entrar no nó
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
}

if (!binaryData) {
    throw new Error("Arquivo binário não encontrado. Verifique se o nome do nó de origem está correto.");
}

const rawText = binaryData.toString('utf8');

// 2. O restante do seu processamento OFX
const trnRegex = /<STMTTRN>([\s\S]*?)<\/STMTTRN>/g;
const transactions = [];
let match;

while ((match = trnRegex.exec(rawText)) !== null) {
    const block = match[1];

    const getValue = (tag) => {
        const r = new RegExp(`<${tag}>([^<\\n\\r]+)`, 'i');
        const m = block.match(r);
        return m ? m[1].trim() : null;
    };

    const dateRaw = getValue('DTPOSTED');
    const amountStr = getValue('TRNAMT');
    const amount = parseFloat(amountStr);

    if (dateRaw && amountStr) {
        transactions.push({
            json: {
                d: `${dateRaw.substring(6,8)}/${dateRaw.substring(4,6)}/${dateRaw.substring(0,4)}`,
                t: getValue('MEMO') || getValue('NAME') || "TRANSACAO OFX",
                v: Math.abs(amount),
                s: amount < 0 ? '-' : '+',
                c: null
            }
        });
    }
}

return transactions;
